css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
}

body {
  background-color: #0a0e1a;
  color: #ffffff;
  display: flex;
  justify-content: center;
  padding: 30px 16px;
  min-height: 100vh;
}

.app {
  width: 100%;
  max-width: 420px;
  text-align: center;
}

h1 {
  font-size: 26px;
  font-weight: 800;
  margin-bottom: 6px;
}

.subtitle {
  color: rgba(255, 255, 255, 0.4);
  font-size: 13.5px;
  margin-bottom: 24px;
}

.stats {
  display: flex;
  gap: 10px;
  margin-bottom: 24px;
}

.stat-box {
  flex: 1;
  background-color: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
  padding: 12px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.stat-label {
  font-size: 11px;
  color: rgba(255, 255, 255, 0.4);
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.stat-value {
  font-size: 20px;
  font-weight: 800;
  font-variant-numeric: tabular-nums;
}

.board {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 10px;
  margin-bottom: 24px;
}

.card {
  aspect-ratio: 1;
  border-radius: 12px;
  cursor: pointer;
  position: relative;
  perspective: 600px;
}

.card-inner {
  width: 100%;
  height: 100%;
  position: relative;
  transition: transform 0.4s;
  transform-style: preserve-3d;
}

.card.flipped .card-inner,
.card.matched .card-inner {
  transform: rotateY(180deg);
}

.card-face {
  position: absolute;
  width: 100%;
  height: 100%;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 30px;
  backface-visibility: hidden;
}

.card-front {
  background-color: rgba(99, 102, 241, 0.15);
  border: 1px solid rgba(99, 102, 241, 0.25);
  color: rgba(255, 255, 255, 0.25);
  font-size: 22px;
  font-weight: 800;
}

.card-back {
  background-color: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
  transform: rotateY(180deg);
}

.card.matched .card-back {
  background-color: rgba(74, 222, 128, 0.12);
  border-color: rgba(74, 222, 128, 0.3);
}

.restart-btn {
  background-color: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.12);
  color: #ffffff;
  padding: 13px 30px;
  border-radius: 999px;
  font-size: 14px;
  font-weight: 700;
  cursor: pointer;
}

.win-message {
  position: fixed;
  inset: 0;
  background-color: rgba(0, 0, 0, 0.7);
  display: none;
  align-items: center;
  justify-content: center;
  padding: 20px;
  z-index: 10;
}

.win-message.show {
  display: flex;
}

.win-content {
  background-color: #14182a;
  border-radius: 16px;
  padding: 32px;
  text-align: center;
  max-width: 320px;
  width: 100%;
}

.win-content h2 {
  font-size: 24px;
  font-weight: 800;
  margin-bottom: 12px;
}

.win-content p {
  color: rgba(255, 255, 255, 0.6);
  font-size: 14px;
  margin-bottom: 22px;
}

.win-content button {
  background-color: #6366f1;
  border: none;
  color: #ffffff;
  padding: 13px 28px;
  border-radius: 999px;
  font-size: 14px;
  font-weight: 700;
  cursor: pointer;
}

js:
var icons = ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H'];
var cards = [];
var flippedCards = [];
var matchedCount = 0;
var moveCount = 0;
var timerInterval = null;
var secondsElapsed = 0;
var lockBoard = false;

function shuffle(array) {
  for (var i = array.length - 1; i > 0; i--) {
    var j = Math.floor(Math.random() * (i + 1));
    var temp = array[i];
    array[i] = array[j];
    array[j] = temp;
  }
  return array;
}

function buildDeck() {
  var deck = [];
  for (var i = 0; i < icons.length; i++) {
    deck.push(icons[i]);
    deck.push(icons[i]);
  }
  return shuffle(deck);
}

function renderBoard() {
  var board = document.getElementById('board');
  board.innerHTML = '';

  for (var i = 0; i < cards.length; i++) {
    var value = cards[i];
    var card = document.createElement('div');
    card.className = 'card';
    card.setAttribute('data-index', i);

    var inner = document.createElement('div');
    inner.className = 'card-inner';

    var front = document.createElement('div');
    front.className = 'card-face card-front';
    front.textContent = '?';

    var back = document.createElement('div');
    back.className = 'card-face card-back';
    back.textContent = value;

    inner.appendChild(front);
    inner.appendChild(back);
    card.appendChild(inner);

    card.addEventListener('click', function () {
      handleCardClick(this);
    });

    board.appendChild(card);
  }
}

function handleCardClick(card) {
  if (lockBoard) return;
  if (card.classList.contains('flipped') || card.classList.contains('matched')) return;
  if (flippedCards.length >= 2) return;

  if (secondsElapsed === 0 && timerInterval === null) {
    startTimer();
  }

  card.classList.add('flipped');
  flippedCards.push(card);

  if (flippedCards.length === 2) {
    moveCount++;
    document.getElementById('moveCount').textContent = moveCount;
    checkMatch();
  }
}

function checkMatch() {
  var firstIndex = parseInt(flippedCards[0].getAttribute('data-index'));
  var secondIndex = parseInt(flippedCards[1].getAttribute('data-index'));

  if (cards[firstIndex] === cards[secondIndex]) {
    flippedCards[0].classList.add('matched');
    flippedCards[1].classList.add('matched');
    matchedCount++;
    document.getElementById('matchCount').textContent = matchedCount + '/8';
    flippedCards = [];

    if (matchedCount === 8) {
      finishGame();
    }
  } else {
    lockBoard = true;
    setTimeout(function () {
      flippedCards[0].classList.remove('flipped');
      flippedCards[1].classList.remove('flipped');
      flippedCards = [];
      lockBoard = false;
    }, 800);
  }
}

function startTimer() {
  timerInterval = setInterval(function () {
    secondsElapsed++;
    var minutes = Math.floor(secondsElapsed / 60);
    var seconds = secondsElapsed % 60;
    var minutesStr = minutes < 10 ? '0' + minutes : '' + minutes;
    var secondsStr = seconds < 10 ? '0' + seconds : '' + seconds;
    document.getElementById('timeCount').textContent = minutesStr + ':' + secondsStr;
  }, 1000);
}

function finishGame() {
  clearInterval(timerInterval);
  timerInterval = null;
  var minutes = Math.floor(secondsElapsed / 60);
  var seconds = secondsElapsed % 60;
  var minutesStr = minutes < 10 ? '0' + minutes : '' + minutes;
  var secondsStr = seconds < 10 ? '0' + seconds : '' + seconds;
  document.getElementById('winText').textContent = moveCount + ' hamle, ' + minutesStr + ':' + secondsStr + ' sure ile tamamladin!';
  document.getElementById('winMessage').classList.add('show');
}

function restartGame() {
  clearInterval(timerInterval);
  timerInterval = null;
  secondsElapsed = 0;
  moveCount = 0;
  matchedCount = 0;
  flippedCards = [];
  lockBoard = false;

  document.getElementById('moveCount').textContent = '0';
  document.getElementById('timeCount').textContent = '00:00';
  document.getElementById('matchCount').textContent = '0/8';
  document.getElementById('winMessage').classList.remove('show');

  cards = buildDeck();
  renderBoard();
}

restartGame();
